def find_pairs_with_distance(rocks, target_distance):  
    left = 0  
    right = 1  
    pairs = []  

    while right < len(rocks):  
        current_diff = rocks[right] - rocks[left]  

        if current_diff == target_distance:  
            pairs.append(( rocks[left], rocks[right]))  
            left += 1  
            right = left + 1  # Reset the right pointer to one step ahead of the left  
        elif current_diff < target_distance:  
            right += 1  
        else:  
            left += 1  
            if left == right:  
                right += 1  

    if not pairs:  
        print("No pairs found")  
    else:  
        for pair in pairs:  
            print(f"({pair[0]}, {pair[1]})")  


