def max_value(n, w, items):  
    items.sort(key=lambda x: x[0]/x[1], reverse=True)  
    total_value = 0.0  
    for value, weight in items:  
        if w == 0:  
            break  
        if weight <= w:  
            total_value += value  
            w -= weight  
        else:  
            total_value += value * (w / weight)  
            w = 0  
    return round(total_value, 2)  

