def max_tasks(tasks):  
    tasks.sort(key=lambda x: x[1])  # sort by deadline  
    total_time = 0  
    durations = []  

    for duration, deadline in tasks:  
        total_time += duration  
        heapq.heappush(durations, -duration)  
        if total_time > deadline:  
            total_time += heapq.heappop(durations)  # remove longest task  

