def min_magic_cost(grid, n, m):  
    INF = float('inf')  
    dp = [[INF] * m for _ in range(n)]  
    dp[0][0] = grid[0][0] if grid[0][0] != -1 else 0  

    # Collect teleport tiles  
    teleports = []  
    for i in range(n):  
        for j in range(m):  
            if grid[i][j] == -1: 
                teleports.append((i, j))  

    # Priority queue: (cost, x, y)  
    heap = [(dp[0][0], 0, 0)]  
    visited_teleport = False  

    while heap:  
        cost, x, y = heapq.heappop(heap)  

        if cost > dp[x][y]:  
            continue  

        # Normal rig ht/down moves  
        for dx, dy in [(1, 0), (0, 1)]:  
            nx, ny = x + dx, y + dy  
            if 0 <= nx < n and 0 <= ny < m:  
                enter_cost = 0 if grid[nx][ny] == -1 else grid[nx][ny]  
                if dp[nx][ny] > cost + enter_cost:  
                    dp[nx][ny] = cost + enter_cost  
                    heapq.heappush(heap, (dp[nx][ny], nx, ny))  

        # If on tel eport, update all other teleports  
        if grid[x][y] == -1 and not visited_teleport:  
            for tx, ty in teleports:  
