def longest_zigzag_subsequence(arr):  
    n = len(arr)  
    if n == 0:  
        return 0  

    up = [1] * n  
    down = [1] * n  

    for i in range(1, n):  
        for j in range(i):  
            if arr[i] > arr[j]:  
                up[i] = max(up[i], down[j] + 1)  
            elif arr[i] < arr[j]:  
                down[i] = max(down[i], up[j] + 1)  

    return max(max(up), max(down))  

