from functools import lru_cache  
def count_beautiful(n, k):  
    digits = list(map(int, str(n)))  

    @lru_cache(None)  
    def dp(pos, sum_mod_k, tight):  
        if pos == len(digits):  
            return 1 if sum_mod_k == 0 else 0  

        limit = digits[pos] if tight else 9  
        total = 0  

        for d in range(0, limit + 1):  
            total += dp(  
                pos + 1,  
                (sum_mod_k + d) % k,  
                tight and (d == limit)  
            ) 

        return total  

    return dp(0, 0, True)  

def solve(L, R, k):  
    return count_beautiful(R, k) - count_beautiful(L - 1, k)  

